const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const app = express();

app.use(express.json());

const client = new Client({ node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200' });

const ALLOWED_INDICES = process.env.ALLOWED_INDICES ? process.env.ALLOWED_INDICES.split(',') : ['logs-*', 'metrics-*', 'analytics-*'];
const FORBIDDEN_INDICES = ['.security*', '.kibana*', '.elastic*', '.monitoring*', '.watcher*', '.ml*'];

const MAX_QUERY_SIZE = 10000;
const MAX_QUERY_DEPTH = 5;

function validateIndexName(indexName) {
  if (!indexName || typeof indexName !== 'string') {
    return false;
  }

  for (const forbidden of FORBIDDEN_INDICES) {
    const pattern = forbidden.replace('*', '.*');
    if (new RegExp(`^${pattern}$`).test(indexName)) {
      return false;
    }
  }

  let isAllowed = false;
  for (const allowed of ALLOWED_INDICES) {
    const pattern = allowed.replace('*', '.*');
    if (new RegExp(`^${pattern}$`).test(indexName)) {
      isAllowed = true;
      break;
    }
  }

  return isAllowed;
}

function calculateDepth(obj, currentDepth = 0) {
  if (currentDepth > MAX_QUERY_DEPTH) {
    return currentDepth;
  }
  
  if (typeof obj !== 'object' || obj === null) {
    return currentDepth;
  }

  let maxDepth = currentDepth;
  for (const key in obj) {
    const depth = calculateDepth(obj[key], currentDepth + 1);
    maxDepth = Math.max(maxDepth, depth);
  }

  return maxDepth;
}

function sanitizeQuery(query) {
  if (!query || typeof query !== 'object') {
    throw new Error('Invalid query format');
  }

  const queryStr = JSON.stringify(query);
  if (queryStr.length > MAX_QUERY_SIZE) {
    throw new Error('Query size exceeds maximum allowed limit');
  }

  if (calculateDepth(query) > MAX_QUERY_DEPTH) {
    throw new Error('Query nesting depth exceeds maximum allowed limit');
  }

  const dangerousOperations = ['script', 'update_by_query', 'delete_by_query', 'reindex'];
  const checkForDangerousOps = (obj) => {
    if (typeof obj !== 'object' || obj === null) return;
    
    for (const key in obj) {
      if (dangerousOperations.includes(key)) {
        throw new Error(`Dangerous operation '${key}' is not allowed`);
      }
      checkForDangerousOps(obj[key]);
    }
  };

  checkForDangerousOps(query);

  if (!query.size || query.size > 1000) {
    query.size = 100;
  }

  if (!query.from || query.from < 0) {
    query.from = 0;
  }

  if (query.from > 10000) {
    throw new Error('Pagination offset too large');
  }

  return query;
}

app.post('/api/search/:index', async (req, res) => {
  try {
    const indexName = req.params.index;

    if (!validateIndexName(indexName)) {
      return res.status(403).json({ 
        error: 'Access denied',
        message: 'Index access is not allowed or index name is invalid'
      });
    }

    const sanitizedQuery = sanitizeQuery(req.body.query || {});

    const result = await client.search({
      index: indexName,
      body: sanitizedQuery,
      timeout: '30s',
      allow_no_indices: false,
      ignore_unavailable: false
    });

    res.json({
      success: true,
      data: result.hits,
      total: result.hits.total,
      took: result.took
    });

  } catch (error) {
    console.error('Search error:', error.message);
    
    if (error.message.includes('not allowed') || error.message.includes('exceeds maximum')) {
      return res.status(400).json({ 
        error: 'Invalid request',
        message: error.message 
      });
    }

    res.status(500).json({ 
      error: 'Search failed',
      message: 'An error occurred while processing your search request'
    });
  }
});

app.get('/api/allowed-indices', (req, res) => {
  res.json({
    success: true,
    indices: ALLOWED_INDICES
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Elasticsearch API running on port ${PORT}`);
  console.log(`Allowed indices: ${ALLOWED_INDICES.join(', ')}`);
});

module.exports = app;